import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';
import Purchases from './pages/Purchases.js';
import Vendors from './pages/Vendors.js';
import Outflow from './pages/Outflow.js';
import MaterialList from './pages/MaterialList.js';
import Projects from './pages/Projects.js';
import ProjectOutflows from './pages/ProjectOutflows.js';
import Stock from './pages/Stock.js';
import Login from './pages/Login.js';

import './App.css';

const API_BASE_URL = 'http://localhost:8081';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const navigate = useNavigate();

  // Check for the presence of the authentication token in cookies
  useEffect(() => {
    const authTokenCookie = document.cookie.split('; ').find((row) => row.startsWith('authToken='));

    if (authTokenCookie) {
      // eslint-disable-next-line no-unused-vars
      const token = authTokenCookie.split('=')[1];

      setIsAuthenticated(true);
    }
  }, []);

  // Handle logout
  const handleLogout = () => {
    // Clear the authentication cookie
    document.cookie = 'authToken=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;';

    // Update the isAuthenticated state
    setIsAuthenticated(false);

    // Redirect to the login page
    navigate('/');
  };

  return (
    <Router>
    <div className="App">
      <BrowserRouter>
        <nav className="sidebar">
          <ul className="navbar-nav">
            <li className="nav-item">
              <Link to="/Purchases" className="nav-link">
                <span>Inflow</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Outflow" className="nav-link">
                <span>Outflow</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/MaterialList" className="nav-link">
                <span>Material List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Vendors" className="nav-link">
                <span>Vendor List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Projects" className="nav-link">
                <span>Project List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Stock" className="nav-link">
                <span>Stock</span>
              </Link>
            </li>
          </ul>
        </nav>
        <main className="content">
          <header className="header">
            <h1 className="header-title">ROBBIE</h1>
          </header>
          {isAuthenticated ? (
            <>
              <p>You are logged in.</p>
              <button onClick={handleLogout}>Logout</button>
              <Routes>
                <Route
                  path="/Purchases"
                  element={<Purchases apiBaseUrl={API_BASE_URL} />}
                />
                <Route path="/Outflow" element={<Outflow apiBaseUrl={API_BASE_URL} />} />
                <Route path="/Vendors" element={<Vendors apiBaseUrl={API_BASE_URL} />} />
                <Route
                  path="/MaterialList"
                  element={<MaterialList apiBaseUrl={API_BASE_URL} />}
                />
                <Route
                  path="/Projects"
                  element={<Projects apiBaseUrl={API_BASE_URL} />}
                />
                <Route
                  path="/ProjectOutflows"
                  element={<ProjectOutflows apiBaseUrl={API_BASE_URL} />}
                />
                <Route path="/Stock" element={<Stock apiBaseUrl={API_BASE_URL} />} />
                {/* Add other routes for different pages */}
              </Routes>
            </>
          ) : (
            <Login onLogin={(token) => setIsAuthenticated(true)} apiBaseUrl={API_BASE_URL} />
          )}
        </main>
      </BrowserRouter>
    </div>
    </Router>
  );
}

export default App;
